@namespace Lumeo
@implements IAsyncDisposable
@inject ComponentInteropService Interop

<div @attributes="AdditionalAttributes" id="@_elementId" class="@CssClass" style="@StyleString" data-motion-visible="@InitialMotionState">
    @ChildContent
</div>

@code {
    /// <summary>The content that blurs and fades into view as it enters the viewport.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Milliseconds to wait after the element enters the viewport before starting the animation. Default <c>0</c>.</summary>
    [Parameter] public int DelayMs { get; set; } = 0;

    /// <summary>Duration of the blur/fade/slide transition in milliseconds. Default <c>600</c>.</summary>
    [Parameter] public int DurationMs { get; set; } = 600;

    /// <summary>Starting blur radius in pixels, animated down to 0 as the element reveals. Default <c>8</c>.</summary>
    [Parameter] public int BlurPx { get; set; } = 8;

    /// <summary>Starting vertical offset in pixels, animated down to 0 as the element reveals. Default <c>8</c>.</summary>
    [Parameter] public int Yoffset { get; set; } = 8;

    /// <summary>When true (default), the reveal animation plays only the first time the element enters the viewport; when false, it replays on every entry.</summary>
    [Parameter] public bool Once { get; set; } = true;
    /// <summary>
    /// When true, always start in the hidden state and animate in — even if the element is already
    /// in the viewport at mount. Default (false) is prerender-friendly: above-the-fold BlurFades
    /// stay statically visible to avoid a flash of blurred content on first paint. Set to true for
    /// docs demos or controlled "Replay" scenarios where you always want the animation to play.
    /// </summary>
    [Parameter] public bool ForceHidden { get; set; }
    /// <summary>Additional CSS classes merged onto the root element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes splatted onto the root element; a caller-supplied <c>style</c> is merged with the blur CSS variables rather than overwritten.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _elementId = $"lumeo-blurfade-{Guid.NewGuid():N}";
    private bool _registered;

    private string CssClass => string.Join(" ", new[] { "lumeo-blur-fade", Class }.Where(s => !string.IsNullOrWhiteSpace(s)));

    // When ForceHidden, render the initial hidden state directly via attribute so the very first
    // paint already shows the to-be-animated state. Prevents a one-frame flash of fully-visible
    // content before the JS observer marks it hidden.
    private string? InitialMotionState => ForceHidden ? "false" : null;

    private string StyleString
    {
        get
        {
            var baseStyle = $"--lumeo-blur-px: {BlurPx}px; --lumeo-blur-y: {Yoffset}px; --lumeo-blur-duration: {DurationMs}ms;";

            // The @attributes splat is rendered FIRST so the explicit id/class/style win and a caller
            // can never clobber the JS hookup id or the blur CSS variables. For style specifically we
            // merge the caller's value onto our own so both the blur variables and the caller's layout
            // styles survive instead of one side silently dropping the other.
            if (AdditionalAttributes is not null
                && AdditionalAttributes.TryGetValue("style", out var callerStyle)
                && callerStyle?.ToString() is { } s
                && !string.IsNullOrWhiteSpace(s))
            {
                return $"{baseStyle} {s.Trim()}";
            }

            return baseStyle;
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && !_registered)
        {
            _registered = true;
            try
            {
                await Interop.MotionBlurFade(_elementId, DelayMs, Once, ForceHidden);
            }
            catch (JSDisconnectedException) { }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (!_registered) return;
        try { await Interop.MotionDisposeObserver(_elementId); }
        catch (JSDisconnectedException) { }
    }
}
